// aggregateSpend rolls receipts up by one of: month, warehouse, department.
// department uses line-item amounts (itemDepartmentNumber); month and warehouse
// use receipt totals. Returns rows sorted by total (or month) descending.
func aggregateSpend(receipts []costcoReceipt, by string) ([]spendRow, error) {
	by = strings.ToLower(strings.TrimSpace(by))
	if by == "" {
		by = "month"
	}
	if !validSpendDimension(by) {
		return nil, fmt.Errorf("--by must be one of: month, warehouse, department (got %q)", by)
	}
	agg := map[string]*spendRow{}
	add := func(key string, amount float64) {
		if agg[key] == nil {
			agg[key] = &spendRow{Key: key}
		}
		agg[key].Count++
		agg[key].Total += amount
	}
	switch by {
	case "month":
		for _, r := range receipts {
			add(monthKey(r.TransactionDate), r.Total.float())
		}
	case "warehouse":
		for _, r := range receipts {
			key := r.WarehouseName
			if key == "" {
				key = r.WarehouseNumber.String()
			}
			if key == "" {
				key = "unknown"
			}
			add(key, r.Total.float())
		}
	case "department":
		for _, r := range receipts {
			for _, it := range r.ItemArray {
				dept := it.DepartmentNumber.String()
				if dept == "" {
					dept = "unknown"
				}
				add(dept, it.Amount.float())
			}
		}
	}
	label := "receipts"
	if by == "department" {
		label = "items"
	}
	rows := make([]spendRow, 0, len(agg))
	for _, v := range agg {
		v.CountLabel = label
		rows = append(rows, *v)
	}
	if by == "month" {
		sort.Slice(rows, func(i, j int) bool { return rows[i].Key > rows[j].Key })
	} else {
		sort.Slice(rows, func(i, j int) bool {
			if rows[i].Total != rows[j].Total {
				return rows[i].Total > rows[j].Total
			}
			return rows[i].Key < rows[j].Key
		})
	}
	return rows, nil
}

// monthKey extracts YYYY-MM from a transaction date, tolerating extra suffixes.
func monthKey(date string) string {
	d := strings.TrimSpace(date)
	if len(d) >= 7 {
		return d[:7]
	}
	if d == "" {
		return "unknown"
	}
	return d
}

